 53	export const alertingRuleSource = (rule: Rule): AlertSource | string => {
 54	  if (rule.sourceId === undefined || rule.sourceId === 'prometheus') {
 55	    return rule.labels?.prometheus === 'openshift-monitoring/k8s'
 56	      ? AlertSource.Platform
 57	      : AlertSource.User;
 58	  }
 59	
 60	  return rule.sourceId;
 61	};
