330	        <DescriptionListTerm>
331	          <strong>{t('Platform: ')}</strong>
332	        </DescriptionListTerm>
333	        <DescriptionListDescription>
334	          {t(
335	            'Platform-level alerts relate only to OpenShift namespaces. OpenShift namespaces provide core OpenShift functionality.',
336	          )}
337	        </DescriptionListDescription>
338	      </DescriptionListGroup>
339	      <DescriptionListGroup>
340	        <DescriptionListTerm>
341	          <strong>{t('User: ')}</strong>
342	        </DescriptionListTerm>
343	        <DescriptionListDescription>
344	          {t(
