392	export const severityRowFilter = (t): RowFilter => ({
393	  filter: (filter, alert: Alert) =>
394	    filter.selected?.includes(alert.labels?.severity) || _.isEmpty(filter.selected),
395	  filterGroupName: t('Severity'),
396	  items: [
397	    { id: AlertSeverity.Critical, title: t('Critical') },
