364	export const SeverityCounts: React.FC<{ alerts: Alert[] }> = ({ alerts }) => {
365	  if (_.isEmpty(alerts)) {
366	    return <>-</>;
367	  }
368	
369	  const counts = _.countBy(alerts, (a) => {
370	    const { severity } = a.labels;
371	    return severity === AlertSeverity.Critical || severity === AlertSeverity.Warning
372	      ? severity
373	      : AlertSeverity.Info;
374	  });
375	
376	  const severities = [AlertSeverity.Critical, AlertSeverity.Warning, AlertSeverity.Info].filter(
377	    (s) => counts[s] > 0,
378	  );
379	
380	  return (
381	    <>
382	      {severities.map((s) => (
383	        <span className="monitoring-icon-wrap" key={s}>
384	          <SeverityIcon severity={s} /> {counts[s]}
385	        </span>
386	      ))}
387	    </>
388	  );
389	};
